 386→interface ColorPickerViewProps {
 387→  colors: ColorItemData[];
 388→  onActiveIndexChange: (index: number) => void;
 389→  onAction: (index: number) => void;
 390→}
 391→
 392→function ColorPickerView({
 393→  colors,
 394→  onActiveIndexChange,
 395→  onAction,
 396→}: ColorPickerViewProps) {
 397→  if (colors.length === 0) {
 398→    return (
 399→      <EmptyState
 400→        icon={<SearchIcon />}
 401→        title="No Colors"
 402→        description="Try a different search term"
 403→      />
 404→    );
 405→  }
 406→
 407→  return (
 408→    <Grid
 409→      itemCount={colors.length}
 410→      columns={4}
 411→      onActiveIndexChange={onActiveIndexChange}
 412→      onAction={onAction}
 413→    >
 414→      {colors.map((color, index) => (
 415→        <GridItem
 416→          key={color.id}
 417→          index={index}
 418→          icon={<ColorSwatch color={color.color} />}
 419→          title={color.title}
 420→          subtitle={color.subtitle}
 421→        />
 422→      ))}
 423→    </Grid>
 424→  );
 425→}
