 444→export function App() {
 445→  const [query, setQuery] = useState('');
 446→  const [filterValue, setFilterValue] = useState('all');
 447→  const [selectedIndex, setSelectedIndex] = useState(0);
 448→  const [actionsOpen, setActionsOpen] = useState(false);
 449→  const { toasts, show: showToast, hide: hideToast } = useToast();
 450→  const { items: hudItems, show: showHUD } = useHUD();
 451→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 452→  const nav = useNavigationStack<NavViewData>('Raycast');
 453→  const { push, pop } = nav;
 454→
 455→  const viewType = nav.currentEntry?.data.type ?? 'root';
 456→
 457→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 458→    () => [
 459→      {
 460→        options: [
 461→          {
 462→            label: 'All',
 463→            value: 'all',
 464→          },
 465→        ],
 466→      },
 467→      {
 468→        title: 'Types',
 469→        options: [
 470→          {
 471→            label: 'Commands',
 472→            value: 'commands',
 473→          },
 474→          {
 475→            label: 'Applications',
 476→            value: 'applications',
 477→          },
 478→        ],
 479→      },
 480→    ],
 481→    [],
 482→  );
 483→
 484→  useEffect(() => {
