 493→  const filtered = useMemo(() => {
 494→    let sections = MOCK_SECTIONS;
 495→    if (filterValue === 'commands') {
 496→      sections = sections.filter(
 497→        s => s.title === 'Suggestions' || s.title === 'Commands',
