 506→  ]);
 507→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
 508→  const filteredColors = useMemo(
 509→    () => filterColors(MOCK_COLORS, query),
 510→    [query],
 511→  );
 512→
 513→  const selectedItem =
 514→    viewType === 'root' ? allItems[selectedIndex] : undefined;
 515→
 516→  const handleQueryChange = useCallback((value: string) => {
 517→    setQuery(value);
 518→    setSelectedIndex(0);
 519→    setActionsOpen(false);
 520→  }, []);
 521→
 522→  const handleFilterChange = useCallback((value: string) => {
 523→    setFilterValue(value);
 524→    setSelectedIndex(0);
 525→  }, []);
 526→
 527→  const handleActiveIndexChange = useCallback((index: number) => {
