 676→                title: 'Detail panel toggled',
 677→              });
 678→            },
 679→          },
 680→          {
 681→            label: 'Create Snippet',
 682→            shortcut: (
 683→              <Kbd
 684→                keys={[
 685→                  '⌘',
 686→                  'N',
 687→                ]}
 688→              />
 689→            ),
 690→            onClick: handleOpenCreateSnippet,
 691→          },
 692→        ],
 693→      },
 694→      {
 695→        title: 'Copy Actions',
