import { useCallback, useEffect, useMemo, useState } from 'react';
import { ActionPanel } from './components/action_panel/action_panel';
import { Alert } from './components/alert/alert';
import { ClipboardHistoryView } from './components/clipboard_history/clipboard_history_view';
import { CommandPalette } from './components/command_palette/command_palette';
import { Detail } from './components/detail/detail';
import { DetailMetadata } from './components/detail/detail_metadata';
import { EmptyState } from './components/empty_state/empty_state';
import {
  Form,
  FormCheckbox,
  FormDatePicker,
  FormDropdown,
  FormTagPicker,
  FormTextArea,
  FormTextField,
} from './components/form';
import { Grid, GridItem } from './components/grid';
import { HUDContainer } from './components/hud/hud_container';
import { Kbd } from './components/kbd/kbd';
import { List, ListItem, ListSection } from './components/list';
import { SearchBar } from './components/search_bar/search_bar';
import type { SearchDropdownSection } from './components/search_bar/search_dropdown';
import { SearchDropdown } from './components/search_bar/search_dropdown';
import { ToastContainer } from './components/toast/toast_container';
import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
import { useAlert } from './hooks/use_alert';
import { useHUD } from './hooks/use_hud';
import { useKeyboardShortcut } from './hooks/use_keyboard_shortcut';
import {
  NavigationContextProvider,
  useNavigationStack,
} from './hooks/use_navigation';
import { useToast } from './hooks/use_toast';
import type {
  ColorItemData,
  ListItemData,
  ListItemMetadataEntry,
  SectionData,
} from './types';

type NavViewData =
  | { type: 'grid' }
  | { type: 'form' }
  | { type: 'clipboard' }
  | {
      type: 'detail';
      item: ListItemData;
    };

function filterSections(sections: SectionData[], query: string): SectionData[] {
  if (!query) return sections;
  const lower = query.toLowerCase();
  return sections
    .map(section => ({
      ...section,
      items: section.items.filter(
        item =>
          item.title.toLowerCase().includes(lower) ||
          item.subtitle?.toLowerCase().includes(lower),
      ),
    }))
    .filter(section => section.items.length > 0);
}

function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  if (!query) return colors;
  const lower = query.toLowerCase();
  return colors.filter(
    c =>
      c.title.toLowerCase().includes(lower) ||
      c.subtitle?.toLowerCase().includes(lower),
  );
}

function flattenItems(sections: SectionData[]): ListItemData[] {
  return sections.flatMap(s => s.items);
}

function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  switch (entry.type) {
    case 'label':
      return (
        <DetailMetadata.Label
          key={index}
          title={entry.title}
          text={entry.text}
        />
      );
    case 'link':
      return (
        <DetailMetadata.Link
          key={index}
          title={entry.title}
          text={entry.text}
          target={entry.target}
        />
      );
    case 'tag-list':
      return (
        <DetailMetadata.TagList key={index} title={entry.title}>
          {entry.tags.map(tag => (
            <DetailMetadata.Tag
              key={tag.text}
              text={tag.text}
              color={tag.color}
            />
          ))}
        </DetailMetadata.TagList>
      );
    case 'separator':
      return <DetailMetadata.Separator key={index} />;
  }
}

function ColorSwatch({ color }: { color: string }) {
  return (
    <div
      className="grid-item__color-swatch"
      style={{ backgroundColor: color }}
    />
  );
}

function CheckIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M3.5 8.5L6.5 11.5L12.5 4.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ClipboardHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <rect
        x="4"
        y="2"
        width="8"
        height="12"
        rx="1.5"
        stroke="currentColor"
        strokeWidth="1.5"
      />
      <path
        d="M6 2.5H10"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

function SearchIcon() {
  return (
    <svg
      width="48"
      height="48"
      viewBox="0 0 48 48"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
      <line
        x1="30"
        y1="30"
        x2="42"
        y2="42"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

interface SnippetFormState {
  name: string;
  keyword: string;
  snippet: string;
  category: string;
  tags: string[];
  isShared: boolean;
  expiresAt: string;
}

const INITIAL_SNIPPET_FORM: SnippetFormState = {
  name: '',
  keyword: '',
  snippet: '',
  category: 'general',
  tags: [],
  isShared: false,
  expiresAt: '',
};

const SNIPPET_TAGS = [
  {
    label: 'JavaScript',
    value: 'javascript',
  },
  {
    label: 'TypeScript',
    value: 'typescript',
  },
  {
    label: 'Python',
    value: 'python',
  },
  {
    label: 'React',
    value: 'react',
  },
  {
    label: 'CSS',
    value: 'css',
  },
  {
    label: 'HTML',
    value: 'html',
  },
  {
    label: 'Shell',
    value: 'shell',
  },
  {
    label: 'Markdown',
    value: 'markdown',
  },
];

const SNIPPET_CATEGORIES = [
  {
    label: 'General',
    value: 'general',
  },
  {
    label: 'Code',
    value: 'code',
  },
  {
    label: 'Email',
    value: 'email',
  },
  {
    label: 'Template',
    value: 'template',
  },
];

interface CreateSnippetViewProps {
  onSubmit: (form: SnippetFormState) => void;
}

function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
  const [snippetForm, setSnippetForm] =
    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
  const [formErrors, setFormErrors] = useState<
    Partial<Record<keyof SnippetFormState, string>>
  >({});

  const handleSubmit = useCallback(() => {
    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
    if (!snippetForm.name.trim()) {
      errors.name = 'Name is required';
    }
    if (!snippetForm.snippet.trim()) {
      errors.snippet = 'Snippet content is required';
    }
    setFormErrors(errors);
    if (Object.keys(errors).length > 0) {
      return;
    }
    onSubmit(snippetForm);
  }, [
    snippetForm,
    onSubmit,
  ]);

  useKeyboardShortcut(
    {
      key: 'Enter',
      meta: true,
    },
    handleSubmit,
  );

  return (
    <Form onSubmit={handleSubmit}>
      <FormTextField
        label="Name"
        value={snippetForm.name}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            name: v,
          }))
        }
        placeholder="e.g. Email Signature"
        error={formErrors.name}
        autoFocus
      />
      <FormTextField
        label="Keyword"
        value={snippetForm.keyword}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            keyword: v,
          }))
        }
        placeholder="e.g. !sig"
        description="Type this to expand the snippet"
      />
      <FormDropdown
        label="Category"
        value={snippetForm.category}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            category: v,
          }))
        }
        options={SNIPPET_CATEGORIES}
        placeholder="Select a category"
      />
      <FormTagPicker
        label="Tags"
        value={snippetForm.tags}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            tags: v,
          }))
        }
        options={SNIPPET_TAGS}
        placeholder="Add tags..."
        description="Categorize your snippet with tags"
      />
      <FormTextArea
        label="Snippet"
        value={snippetForm.snippet}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            snippet: v,
          }))
        }
        placeholder="Enter your snippet content..."
        error={formErrors.snippet}
        rows={5}
      />
      <FormCheckbox
        label="Share with team"
        checked={snippetForm.isShared}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            isShared: v,
          }))
        }
        description="Make this snippet available to your team members"
      />
      <FormDatePicker
        label="Expires"
        value={snippetForm.expiresAt}
        onChange={v =>
          setSnippetForm(prev => ({
            ...prev,
            expiresAt: v,
          }))
        }
        description="Optional expiration date"
      />
    </Form>
  );
}

interface ColorPickerViewProps {
  colors: ColorItemData[];
  onActiveIndexChange: (index: number) => void;
  onAction: (index: number) => void;
}

function ColorPickerView({
  colors,
  onActiveIndexChange,
  onAction,
}: ColorPickerViewProps) {
  if (colors.length === 0) {
    return (
      <EmptyState
        icon={<SearchIcon />}
        title="No Colors"
        description="Try a different search term"
      />
    );
  }

  return (
    <Grid
      itemCount={colors.length}
      columns={4}
      onActiveIndexChange={onActiveIndexChange}
      onAction={onAction}
    >
      {colors.map((color, index) => (
        <GridItem
          key={color.id}
          index={index}
          icon={<ColorSwatch color={color.color} />}
          title={color.title}
          subtitle={color.subtitle}
        />
      ))}
    </Grid>
  );
}

function DetailView({ item }: { item: ListItemData }) {
  const itemDetail = item.detail;
  if (!itemDetail) return null;
  return (
    <Detail
      markdown={itemDetail.markdown}
      metadata={
        itemDetail.metadata ? (
          <DetailMetadata>
            {itemDetail.metadata.map(renderMetadataEntry)}
          </DetailMetadata>
        ) : undefined
      }
    />
  );
}

export function App() {
  const [query, setQuery] = useState('');
  const [filterValue, setFilterValue] = useState('all');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const { toasts, show: showToast, hide: hideToast } = useToast();
  const { items: hudItems, show: showHUD } = useHUD();
  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
  const nav = useNavigationStack<NavViewData>('Raycast');
  const { push, pop } = nav;

  const viewType = nav.currentEntry?.data.type ?? 'root';

  const searchFilterSections: SearchDropdownSection[] = useMemo(
    () => [
      {
        options: [
          {
            label: 'All',
            value: 'all',
          },
        ],
      },
      {
        title: 'Types',
        options: [
          {
            label: 'Commands',
            value: 'commands',
          },
          {
            label: 'Applications',
            value: 'applications',
          },
        ],
      },
    ],
    [],
  );

  useEffect(() => {
    if (nav.stackDepth === 0) {
      setQuery('');
      setFilterValue('all');
      setSelectedIndex(0);
      setActionsOpen(false);
    }
  }, [nav.stackDepth]);

  const filtered = useMemo(() => {
    let sections = MOCK_SECTIONS;
    if (filterValue === 'commands') {
      sections = sections.filter(
        s => s.title === 'Suggestions' || s.title === 'Commands',
      );
    } else if (filterValue === 'applications') {
      sections = sections.filter(s => s.title === 'Applications');
    }
    return filterSections(sections, query);
  }, [
    query,
    filterValue,
  ]);
  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
  const filteredColors = useMemo(
    () => filterColors(MOCK_COLORS, query),
    [query],
  );

  const selectedItem =
    viewType === 'root' ? allItems[selectedIndex] : undefined;

  const handleQueryChange = useCallback((value: string) => {
    setQuery(value);
    setSelectedIndex(0);
    setActionsOpen(false);
  }, []);

  const handleFilterChange = useCallback((value: string) => {
    setFilterValue(value);
    setSelectedIndex(0);
  }, []);

  const handleActiveIndexChange = useCallback((index: number) => {
    setSelectedIndex(index);
    setActionsOpen(false);
  }, []);

  const handleCopyColor = useCallback(
    (color: ColorItemData) => {
      showHUD({
        icon: <ClipboardHUDIcon />,
        title: `Copied ${color.color}`,
      });
    },
    [showHUD],
  );

  const handleGridAction = useCallback(
    (index: number) => {
      const color = filteredColors[index];
      if (color) {
        handleCopyColor(color);
      }
    },
    [
      filteredColors,
      handleCopyColor,
    ],
  );

  const handleSnippetSubmit = useCallback(
    (form: SnippetFormState) => {
      showToast({
        style: 'success',
        title: 'Snippet Created',
        message: form.name,
      });
      pop();
    },
    [
      showToast,
      pop,
    ],
  );

  const handleDrillIn = useCallback(() => {
    const item = allItems[selectedIndex];
    if (!item) return;

    setActionsOpen(false);

    if (item.id === 'clipboard-history') {
      push('Clipboard History', { type: 'clipboard' });
      setQuery('');
      setSelectedIndex(0);
    } else if (item.id === 'color-picker') {
      push('Color Picker', { type: 'grid' });
      setQuery('');
      setSelectedIndex(0);
      showToast({
        style: 'success',
        title: 'Opened Color Picker',
      });
    } else if (item.detail) {
      push(item.title, {
        type: 'detail',
        item,
      });
      setQuery('');
      showToast({
        style: 'success',
        title: `Opened ${item.title}`,
      });
    } else {
      showToast({
        style: 'success',
        title: `Opened ${item.title}`,
      });
    }
  }, [
    allItems,
    selectedIndex,
    showToast,
    push,
  ]);

  const handleOpenCreateSnippet = useCallback(() => {
    setActionsOpen(false);
    push('Create Snippet', { type: 'form' });
    setQuery('');
    setSelectedIndex(0);
  }, [push]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut(
    {
      key: 'k',
      meta: true,
    },
    toggleActions,
    { enabled: viewType !== 'form' && viewType !== 'clipboard' },
  );

  useKeyboardShortcut(
    {
      key: 'n',
      meta: true,
    },
    handleOpenCreateSnippet,
    { enabled: viewType === 'root' },
  );

  const detail = selectedItem?.detail;

  const dropdownSections = useMemo(
    () => [
      {
        title: 'Primary Actions',
        actions: [
          {
            label: 'Open',
            shortcut: <Kbd keys={['↵']} />,
            onClick: () => {
              if (selectedItem) {
                showToast({
                  style: 'success' as const,
                  title: `Opened ${selectedItem.title}`,
                });
              }
            },
          },
          {
            label: 'Show Detail',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'D',
                ]}
              />
            ),
            onClick: () => {
              showToast({
                style: 'info' as const,
                title: 'Detail panel toggled',
              });
            },
          },
          {
            label: 'Create Snippet',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'N',
                ]}
              />
            ),
            onClick: handleOpenCreateSnippet,
          },
        ],
      },
      {
        title: 'Copy Actions',
        actions: [
          {
            label: 'Copy Name',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'C',
                ]}
              />
            ),
            onClick: () => {
              if (selectedItem) {
                showHUD({
                  icon: <CheckIcon />,
