import './clipboard_history_view.scss';

function ClipboardHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <rect
        x="4"
        y="2"
        width="8"
        height="12"
        rx="1.5"
        stroke="currentColor"
        strokeWidth="1.5"
      />
      <path
        d="M6 2.5H10"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

function PinIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M10 1L14 5L11 8V11.5L8.5 14L8 9.5L3.5 9L6 6.5L3 3.5L6 1L8.5 3.5L10 1Z"
        stroke="currentColor"
        strokeWidth="1.25"
